mapper.select:
SELECT noticeId, title, noticeType, isPinned, isPopup, popupStartDt, popupEndDt, targetDeptId, viewCount, attachYn, useYn, createdUser, createdDate, updateUser, updatedDate FROM notice_info
AND title LIKE CONCAT('%', #{title}, '%')
AND noticeType = #{noticeType}
AND useYn = #{useYn}
ORDER BY isPinned DESC, createdDate DESC

mapper.update:
UPDATE notice_info
SET    viewCount = viewCount + 1
WHERE  noticeId = #{noticeId}
